args.sparql:
SELECT ?film WHERE {
  wd:Q1449 wdt:P166 ?award .
  ?award wdt:P585 ?date .
  FILTER (YEAR(?date) = 1979)
  ?award wdt:P1343 ?film
}

SELECT ?film WHERE {
  wd:Q1449 wdt:P166 ?award .
  ?award wdt:P585 ?date .
  FILTER (SUBSTR(str(?date), 1, 4) = "1979")
  ?award wdt:P1343 ?film
}

SELECT ?film WHERE {
  wd:Q1449 wdt:P166 ?award .
  ?award wdt:P641 wd:Q529 .
  ?award wdt:P1343 ?film
}

SELECT ?filmLabel WHERE {
  wd:Q1449 wdt:P166 ?award .
  ?award wdt:P641 wd:Q1599135 .
  ?award wdt:P585 ?date .
  FILTER (SUBSTR(str(?date), 1, 4) = "1979")
  ?award wdt:P1343 ?film .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
}

SELECT ?film WHERE {
  wd:Q1449 wdt:P166 ?award .
  ?award wdt:P641 ?film .
  ?award wdt:P585 ?date .
  FILTER (YEAR(?date) = 1979)
}

SELECT ?film WHERE {
  wd:Q1449 wdt:P166 ?award .
  ?award wdt:P1343 ?film
}

SELECT ?filmLabel WHERE {
  wd:Q1449 wdt:P166 ?award .
  ?award wdt:P1343 ?film .
  ?film rdfs:label ?filmLabel .
  FILTER (LANG(?filmLabel) = 'en')
}
